import React from 'react';

const Home = () => {
  return (
    <div className="align-center">
      <h2 className="text-center">ADMIN HOME</h2>
      <img src="https://upload.wikimedia.org/wikipedia/commons/b/b1/Loading_icon.gif?20151024034921" width="300px" alt="Admin Home" />
    </div>
  );
};

export default Home; // <--- QUAN TRỌNG NHẤT LÀ DÒNG NÀY
